import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';

export function useUserRole() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    base44.auth.me().then(u => {
      setUser(u);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  // 'admin' es el rol por defecto de Base44, tratarlo como superadmin
  const role = user?.role === 'admin' ? 'superadmin' : user?.role;
  const isSuperAdmin = role === 'superadmin';
  const isOperador = role === 'operador';
  const isAuditor = role === 'auditor';

  // isAdmin mantiene compatibilidad: superadmin tiene todos los permisos de admin
  const isAdmin = isSuperAdmin;

  // Puede registrar movimientos
  const canWrite = isSuperAdmin || isOperador;

  // Puede editar catálogos (combustibles, precios)
  const canManageCatalogos = isSuperAdmin || isOperador;

  // Puede gestionar tarjetas y vehículos
  const canManageFlota = isSuperAdmin || isOperador;

  // Puede importar datos
  const canImport = isSuperAdmin || isOperador;

  // Puede ver reportes y descargar
  const canViewReportes = isSuperAdmin || isOperador || isAuditor;

  // Puede eliminar registros
  const canDelete = isSuperAdmin;

  // Puede ver todo (auditor + operador + superadmin)
  const canRead = isSuperAdmin || isOperador || isAuditor;

  return {
    user,
    role,
    loading,
    isAdmin,       // alias de isSuperAdmin para compatibilidad
    isSuperAdmin,
    isOperador,
    isAuditor,
    canWrite,
    canManageCatalogos,
    canManageFlota,
    canImport,
    canViewReportes,
    canDelete,
    canRead,
  };
}

