    if (!editing && vehiculos.some(v => v.chapa === form.chapa.trim())) {
      toast.error('Ya existe un vehículo con esa chapa'); return;
    }
    if (editing) {
      updateMut.mutate({ id: editing.id, d: form });
    } else {
      createMut.mutate(form);
